VALUES
  ('elementary-64311456-moex-00155', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '社會工作者接獲通報，得知有一對家長時常將未滿 6 歲的兒童獨留在家。面對此情境的社會工作者可基 於何種倫理處理原則加以介入？', '["個人自我決定權優於其自身基本福祉的考量", "個人基本福祉權利與法律相衝突時，個人福祉應優先考量", "人們在自由意志下同意遵守法律之義務，可凌駕於個人價值", "自決的權利不得傷及他人基本福祉"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00156', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '關於社會工作師對社會工作師專業的倫理責任，下列敘述何者正確？', '["社會工作師應增進社會工作專業知能的發展，進行研究及著作發表，遵守社會工作研究倫理", "社會工作師應致力於社會公益的倡導與實踐", "社會工作師應具備社會工作專業技能，不斷充實自我", "社會工作師擔任教育、督導時，應盡力提供專業指導，公平、客觀評量事件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00157', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '社會正義（socialjustice）是社會工作者的靈魂，但社會資源有限則是社會工作者無可避免的議題。因此， 當社會工作者扮演著資源分配者的角色時，應堅守下列那些正義原則？', '["公開透明、社會階級、比例原則、社會補償", "公開透明、就業紀錄、弱勢優先、需求強度", "平等分配、需求強度、弱勢優先、貢獻多寡", "需求強度、公開透明、貢獻多寡、社會階級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00158', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '1980年實施的美國社會工作倫理守則，下列敘述何者正確？', '["社會工作者對於服務機構的批判責任", "社會工作者對同僚的道德責任", "社會工作者對於社會的監督責任", "社會工作者對專業社會工作的研發責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00159', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '樓斯曼（Rothman,1989）提出自決的理論根據，下列敘述何者錯誤？', '["存在的現實", "文化疏離的解藥", "義務論的實施工具", "政治與情緒的解放"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00160', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '在特殊狀況下，社會工作者得不遵守對案主的保密原則。下列何者不屬於特殊狀況的範圍？', '["社會工作者已獲得案主書面同意，並授權在特定狀況下可提供給已設定的對象/單位", "案主面臨生命危險時，雖未獲得授權但可不遵守保密原則", "為提升社會對特定議題的了解，雖未獲案主同意，仍可利用其生命故事警惕世人", "案主面臨法院強制提供通知、或有兒童虐待等舉報，可不遵守保密原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00161', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '關於社區工作的實施，與社區民眾接觸是重要的工作過程，下列敘述何者錯誤？', '["社會工作者必須在事前對於社區居民生活的環境有一定的認識", "與社區民眾接觸重要的是認識對方，因此社會工作者為了自己的交通與時間考量，不一定要在社區碰面", "社會工作者必須注重自己帶給居民的第一印象", "社會工作者需要設想社區居民可能提出來的問題，預先做好準備"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00162', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '建立合法組織對於社區工作發展的主要意義，下列何者正確？', '["成立合法代表性的組織，建立穩定發展的制度與資源管理機制", "避免社區組織成為犯罪的管道", "設立嚴格的入會門檻，保障社區發展的品質", "協助社區領袖累積民意基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00163', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '下列何者是Rothman與Tropman（1987）提出的社會計畫模式主要目標？', '["解決社區實質問題，著重任務目標", "社區能力與整合，著重過程目標", "改變權力關係與資源，著重過程與任務目標", "以自助合作程序做決策解決問題，著重過程目標"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00164', 'elementary-64311456', 'elementary-64311456-moex-114-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '在社區發展的過程中，工作者和居民一同工作，同時須培養社區居民發掘問題、解決問題的能力，並規劃 適當的歷程將社區發展的要務移轉交回給社區，此項社區工作的歷程任務，最主要是回應下列何者社區工 作的目標？', '["瞭解社區需求", "設定社區發展願景", "促進社區居民互動", "社區永續經營"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:07+00:00", "source_pdf_sha1": "2b3770e8743a", "answer_pdf_sha1": "e496b24c7c76", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "505", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
